-- Piper AI Agent - PostgreSQL Schema
-- Requires PostgreSQL 16 + pgvector extension

CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE EXTENSION IF NOT EXISTS "vector";

-- ============================================
-- Users
-- ============================================
CREATE TABLE users (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    email VARCHAR(255) UNIQUE NOT NULL,
    password_hash VARCHAR(255) NOT NULL,
    display_name VARCHAR(100),
    is_active BOOLEAN DEFAULT TRUE,
    created_at TIMESTAMP DEFAULT NOW(),
    last_login_at TIMESTAMP
);

CREATE INDEX idx_users_email ON users (email);

-- ============================================
-- Products
-- ============================================
CREATE TABLE products (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    product_name VARCHAR(255) NOT NULL,
    description TEXT,
    price DECIMAL(10, 2) NOT NULL,
    manufacturing_date DATE,
    warranty_months INTEGER DEFAULT 0,
    created_at TIMESTAMP DEFAULT NOW()
);

CREATE INDEX idx_products_name ON products (product_name);
CREATE INDEX idx_products_price ON products (price);

-- ============================================
-- Product Embeddings (pgvector)
-- ============================================
CREATE TABLE product_embeddings (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    product_id UUID NOT NULL REFERENCES products(id) ON DELETE CASCADE,
    embedding vector(1024) NOT NULL,
    created_at TIMESTAMP DEFAULT NOW()
);

CREATE INDEX idx_product_embeddings_ivfflat
    ON product_embeddings USING ivfflat (embedding vector_cosine_ops)
    WITH (lists = 10);

-- ============================================
-- Sessions
-- ============================================
CREATE TABLE sessions (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    customer_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    metadata JSONB DEFAULT '{}',
    created_at TIMESTAMP DEFAULT NOW(),
    last_active_at TIMESTAMP DEFAULT NOW()
);

CREATE INDEX idx_sessions_customer ON sessions (customer_id);
CREATE INDEX idx_sessions_last_active ON sessions (last_active_at);

-- ============================================
-- Conversation Turns
-- ============================================
CREATE TABLE conversation_turns (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    session_id UUID NOT NULL REFERENCES sessions(id) ON DELETE CASCADE,
    role VARCHAR(20) NOT NULL CHECK (role IN ('user', 'assistant', 'system')),
    content TEXT NOT NULL,
    intent VARCHAR(50),
    confidence REAL,
    tool_calls JSONB DEFAULT '[]',
    created_at TIMESTAMP DEFAULT NOW()
);

CREATE INDEX idx_conversation_turns_session ON conversation_turns (session_id, created_at);

-- ============================================
-- Episodic Memories → Moved to TimescaleDB
-- See db/timescaledb_init.sql for the immutable
-- hypertable definition and session audit trail.
-- ============================================

-- ============================================
-- Query Patterns (for recommendations)
-- ============================================
CREATE TABLE query_patterns (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    query_text TEXT NOT NULL UNIQUE,
    intent VARCHAR(50),
    frequency INTEGER DEFAULT 1,
    last_seen TIMESTAMP DEFAULT NOW()
);

CREATE INDEX idx_query_patterns_freq ON query_patterns (frequency DESC);

-- ============================================
-- Tool Definitions
-- ============================================
CREATE TABLE tool_definitions (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    name VARCHAR(100) UNIQUE NOT NULL,
    description TEXT NOT NULL,
    parameter_schema JSONB NOT NULL DEFAULT '{}',
    is_active BOOLEAN DEFAULT TRUE,
    created_at TIMESTAMP DEFAULT NOW()
);

-- ============================================
-- Tool Execution Logs
-- ============================================
CREATE TABLE tool_execution_logs (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    session_id UUID REFERENCES sessions(id) ON DELETE SET NULL,
    tool_id UUID REFERENCES tool_definitions(id) ON DELETE SET NULL,
    input_params JSONB DEFAULT '{}',
    output_result JSONB DEFAULT '{}',
    execution_time_ms INTEGER,
    status VARCHAR(20) DEFAULT 'success'
        CHECK (status IN ('success', 'error', 'timeout')),
    created_at TIMESTAMP DEFAULT NOW()
);

CREATE INDEX idx_tool_logs_session ON tool_execution_logs (session_id, created_at);

